def parse_entry(e):
    ref = e['ref_text'] or ""
    result = {
        "span_start": e['span_start'],
        "span_end": e['span_end'],
        "span_text": e['span_text'],
    }
    # Default
    result["corrected_text"] = "خطأ"
    result["completely_invalid"] = True
    result["is_valid"] = False
    
    aya_ref = {}
    hadith_ref = {}
    if ":" in ref and "رواه" not in ref:
        # Quran
        parts = [p.strip() for p in ref.split(":")]
        sura_name = parts[0]
        aya_part = parts[1] if len(parts) > 1 else ""
        # If aya_part contains a hyphen, it's a range; else integer
        try:
            if "-" in aya_part:
                aya_num = None
            else:
                aya_num = int(aya_part)
        except:
            aya_num = None
        aya_ref = {"sura_name": sura_name, "sura_number": sura_map.get(sura_name)}
        if aya_num is not None:
            aya_ref["aya_number"] = aya_num
        result["citation_type"] = "Aya"
        result["aya_reference"] = aya_ref
        result["hadeeth_reference"] = {}
    elif "رواه البخاري" in ref:
        result["citation_type"] = "Hadeeth"
        hadith_ref = {"collection_name": "Sahih Bukhari"}
        result["hadeeth_reference"] = hadith_ref
        result["aya_reference"] = {}
    elif "رواه مسلم" in ref:
        result["citation_type"] = "Hadeeth"
        hadith_ref = {"collection_name": "Sahih Muslim"}
        result["hadeeth_reference"] = hadith_ref
        result["aya_reference"] = {}
    else:
        # Unknown type?
        result["citation_type"] = "Aya"  # default? but here all have reference
        result["aya_reference"] = {}
        result["hadeeth_reference"] = {}
    return result

